 		}
+
+		[TestMethod]
+		[RunsOnUIThread]
+		public async Task When_Window_Resized_Overlay_Updates()
+		{
+			var window = Microsoft.UI.Xaml.Window.Current;
+			var xamlRoot = window.Content?.XamlRoot;
+
+			if (xamlRoot == null)
+			{
+				// Create a basic content if none exists
+				var root = new Grid();
+				window.Content = root;
+				xamlRoot = root.XamlRoot;
+			}
+
+			var dialog = new ContentDialog
+			{
+				Title = "Test Dialog",
+				Content = "This is a test",
+				CloseButtonText = "Close",
+				XamlRoot = xamlRoot
+			};
+
+			// Show the dialog
+			var showTask = dialog.ShowAsync();
+
+			// Wait for the dialog to be displayed
+			await Task.Delay(100);
+
+			// Verify dialog is open
+			Assert.IsTrue(dialog._popup.IsOpen);
+
+			// Get initial size
+			var initialWidth = dialog.ActualWidth;
+			var initialHeight = dialog.ActualHeight;
+
+			// Simulate window resize by triggering XamlRoot.Changed event
+			// This simulates maximize/restore scenario
+			var newSize = new Size(1920, 1080);
+			xamlRoot.RaiseChangedEvent();
+
+			// Wait for layout to update
+			await Task.Delay(100);
+
+			// After resize, dialog should still have proper dimensions
+			// In the bug, the overlay doesn't update correctly
+			Assert.IsTrue(dialog.ActualWidth > 0);
+			Assert.IsTrue(dialog.ActualHeight > 0);
+
+			// Close the dialog
+			dialog.Hide();
+			await Task.Delay(50);
+		}
 	}
 }
