   126→		private void SetDialogFocus()
   127→		{
   128→			bool focusSet = false;
   129→
   130→			var focusManager = VisualTree.GetFocusManagerForElement(this);
   131→
   132→			if (m_tpContentPart is not null)
   133→			{
   134→				if (focusManager.GetFirstFocusableElement(m_tpContentPart) is UIElement focusableElement)
   135→				{
   136→					focusSet = focusableElement.Focus(FocusState.Programmatic);
   137→				}
   138→			}
   139→
   140→			if (!focusSet)
   141→			{
   142→				ButtonBase button = DefaultButton switch
   143→				{
   144→					ContentDialogButton.Primary => m_tpPrimaryButtonPart,
   145→					ContentDialogButton.Secondary => m_tpSecondaryButtonPart,
   146→					ContentDialogButton.Close => m_tpCloseButtonPart,
   147→					_ => null,
   148→				};
   149→				focusSet = button?.Focus(FocusState.Programmatic) ?? false;
   150→			}
   151→
   152→			if (!focusSet && m_tpCommandSpacePart is not null)
   153→			{
   154→				if (focusManager.GetFirstFocusableElement(m_tpCommandSpacePart) is UIElement focusableCommandElement)
   155→				{
