   201→		internal bool Hide(ContentDialogResult result)
   202→		{
   203→			_hiding = true;
   204→			void Complete(ContentDialogClosingEventArgs args)
   205→			{
   206→				if (!args.Cancel)
   207→				{
   208→					m_isShowing = false;
   209→					_popup.IsOpen = false;
   210→					_popup.Child = null;
   211→					UpdateVisualState();
   212→					Closed?.Invoke(this, new ContentDialogClosedEventArgs(result));
   213→
   214→					// Make sure all clean-up is done before returning result,
   215→					// to prevent problems when the dialog is reopened synchronously
   216→					(var tcs, _tcs) = (_tcs, null);
   217→					DispatcherQueue.TryEnqueue(() => tcs?.TrySetResult(result));
   218→				}
   219→				_hiding = false;
   220→			}
   221→			var closingArgs = new ContentDialogClosingEventArgs(Complete, result);
   222→
   223→			Closing?.Invoke(this, closingArgs);
   224→
   225→			var completedSynchronously = closingArgs.DeferralManager.EventRaiseCompleted();
   226→
   227→			return completedSynchronously && !closingArgs.Cancel;
   228→		}
