   292→		public IAsyncOperation<ContentDialogResult> ShowAsync()
   293→			=> AsyncOperation.FromTask(async ct =>
   294→			{
   295→				if (_popup.IsOpen)
   296→				{
   297→					throw new InvalidOperationException("A ContentDialog is already opened.");
   298→				}
   299→
   300→#if !HAS_UNO_WINUI
   301→				if (XamlRoot is null &&
   302→					WinUICoreServices.Instance.InitializationType != InitializationType.IslandsOnly)
   303→				{
   304→					XamlRoot = WinUICoreServices.Instance.MainRootVisual?.XamlRoot;
   305→				}
   306→#endif
   307→
   308→				// TODO: support in-place
   309→				m_placementMode = PlacementMode.EntireControlInPopup;
   310→
   311→				// Make sure default template is applied, so visual states etc can be set correctly
   312→				EnsureTemplate();
   313→				if (HasValidAppliedTemplate())
   314→				{
   315→					PrepareContent();
   316→				}
   317→
   318→				_popup.Child = this;
   319→
   320→				m_isShowing = true;
   321→				_popup.IsOpen = true;
   322→				_popup.IsLightDismissEnabled = false;
   323→
   324→				_tcs = new TaskCompletionSource<ContentDialogResult>();
   325→
   326→				using (ct.Register(() =>
   327→				{
   328→					_tcs.TrySetCanceled();
   329→					Hide();
   330→				}
   331→#if !__WASM__ // WASM lacks threading support
   332→					, useSynchronizationContext: true
   333→#endif
   334→					))
   335→				{
   336→					return await _tcs.Task;
   337→				}
   338→			});
