   457→		private void ProcessCloseButton()
   458→		{
   459→			void Complete(ContentDialogButtonClickEventArgs a)
   460→			{
   461→				if (!a.Cancel)
   462→				{
   463→					const ContentDialogResult result = ContentDialogResult.None;
   464→
   465→					CloseButtonCommand.ExecuteIfPossible(CloseButtonCommandParameter);
   466→
   467→					Hide(result);
   468→				}
   469→				else
   470→				{
   471→					_hiding = false;
   472→				}
   473→			}
   474→
   475→			if (_hiding)
   476→			{
   477→				return;
   478→			}
   479→
   480→			var args = new ContentDialogButtonClickEventArgs(Complete);
   481→			CloseButtonClick?.Invoke(this, args);
   482→
