   129→	}
   130→
   131→	protected virtual Rect CalculatePopupPlacement(Popup popup, Size childDesiredSize, Size maxSize)
   132→	{
   133→		var anchorRect = GetAnchorRect(popup);
   134→
   135→		var visibleBounds = GetVisibleBounds();
   136→
   137→		// Make sure the desiredSize fits in the panel
   138→		childDesiredSize.Width = Math.Min(childDesiredSize.Width, visibleBounds.Width);
   139→		childDesiredSize.Height = Math.Min(childDesiredSize.Height, visibleBounds.Height);
   140→
   141→		// Try all placements...
   142→		var preferredPlacement = FlyoutBase.GetMajorPlacementFromPlacement(popup.DesiredPlacement, FullPlacementRequested);
   143→		var placementsToTry = PlacementsToTry.TryGetValue(preferredPlacement, out var p)
   144→			? p
   145→			: new[] { preferredPlacement };
   146→
   147→		if (this.Log().IsEnabled(LogLevel.Debug))
   148→		{
   149→			this.Log().LogDebug($"Calculating actual placement for preferredPlacement={preferredPlacement} with justification={FlyoutBase.GetJustificationFromPlacementMode(popup.DesiredPlacement, FullPlacementRequested)} from PopupPlacement={popup.DesiredPlacement}, for childDesiredSize={childDesiredSize}, maxSize={maxSize}");
   150→		}
   151→
   152→		var halfAnchorWidth = anchorRect.Width / 2;
   153→		var halfAnchorHeight = anchorRect.Height / 2;
   154→		var halfChildWidth = childDesiredSize.Width / 2;
   155→		var halfChildHeight = childDesiredSize.Height / 2;
   156→
   157→		var finalRect = default(Rect);
   158→
   159→		for (var i = 0; i < placementsToTry.Length; i++)
   160→		{
   161→			var placement = placementsToTry.Span[i];
   162→
   163→			Point finalPosition;
   164→
   165→			switch (placement)
   166→			{
   167→				case FlyoutBase.MajorPlacementMode.Top:
   168→					finalPosition = new Point(
   169→						x: anchorRect.Left + halfAnchorWidth - halfChildWidth + popup.HorizontalOffset,
   170→						y: anchorRect.Top - PopupPlacementTargetMargin - childDesiredSize.Height + popup.VerticalOffset);
   171→					break;
   172→				case FlyoutBase.MajorPlacementMode.Bottom:
   173→					finalPosition = new Point(
   174→						x: anchorRect.Left + halfAnchorWidth - halfChildWidth + popup.HorizontalOffset,
   175→						y: anchorRect.Bottom + PopupPlacementTargetMargin + popup.VerticalOffset);
   176→					break;
   177→				case FlyoutBase.MajorPlacementMode.Left:
   178→					finalPosition = new Point(
   179→						x: anchorRect.Left - PopupPlacementTargetMargin - childDesiredSize.Width + popup.HorizontalOffset,
   180→						y: anchorRect.Top + halfAnchorHeight - halfChildHeight + popup.VerticalOffset);
   181→					break;
   182→				case FlyoutBase.MajorPlacementMode.Right:
   183→					finalPosition = new Point(
   184→						x: anchorRect.Right + PopupPlacementTargetMargin + popup.HorizontalOffset,
   185→						y: anchorRect.Top + halfAnchorHeight - halfChildHeight + popup.VerticalOffset);
   186→					break;
   187→				case FlyoutBase.MajorPlacementMode.Full:
   188→					if (FeatureConfiguration.Popup.ConstrainByVisibleBounds)
   189→					{
   190→#if !__APPLE_UIKIT__
   191→						childDesiredSize = visibleBounds.Size;
   192→#else
   193→						// The mobile status bar should always remain visible.
   194→						// On droid, this panel is placed beneath the status bar.
   195→						// On iOS, this panel will cover the status bar, so we have to substract it out.
   196→						childDesiredSize = new Size(ActualWidth, ActualHeight)
   197→							.Subtract(0, visibleBounds.Y)
   198→							.AtMost(maxSize);
   199→#endif
   200→					}
   201→					else
   202→					{
   203→						// When ConstrainByVisibleBounds is false, we let the flyout to occupy the entire area available,
   204→						// as dictated by the root skia-canvas. This extends into the status bar, and bottom bar if present.
   205→#if __SKIA__
   206→						childDesiredSize = m_unclippedDesiredSize;
   207→#else
   208→						childDesiredSize = DesiredSize;
   209→#endif
   210→					}
   211→
   212→					finalPosition = new Point(
   213→#if __SKIA__
   214→						x: FindOptimalOffset(childDesiredSize.Width, visibleBounds.X, visibleBounds.Width, (Parent as FrameworkElement)?.ActualWidth ?? ActualWidth),
   215→						y: FindOptimalOffset(childDesiredSize.Height, visibleBounds.Y, visibleBounds.Height, (Parent as FrameworkElement)?.ActualHeight ?? ActualHeight)
   216→#else
   217→						x: FindOptimalOffset(childDesiredSize.Width, visibleBounds.X, visibleBounds.Width, ActualWidth),
   218→						y: FindOptimalOffset(childDesiredSize.Height, visibleBounds.Y, visibleBounds.Height, ActualHeight)
   219→#endif
   220→					);
   221→
   222→					double FindOptimalOffset(double desired, double visibleOffset, double visibleLength, double constraint)
   223→					{
   224→						// Center the flyout inside the first area that fits: within visible bounds, below status bar, the screen
   225→						if (visibleLength >= desired)
   226→						{
   227→							return visibleOffset + (visibleLength - desired) / 2;
   228→						}
   229→						if (constraint - visibleOffset >= desired)
   230→						{
   231→							return visibleOffset + ((constraint - visibleOffset) - desired) / 2;
   232→						}
   233→						else
   234→						{
   235→							return constraint == 0 ? 0 : (constraint - desired) / 2;
   236→						}
   237→					}
   238→					break;
   239→				default: // Other unsupported placements
   240→					finalPosition = new Point(
   241→						x: (visibleBounds.Width - childDesiredSize.Width) / 2.0,
   242→						y: (visibleBounds.Height - childDesiredSize.Height) / 2.0);
   243→					break;
   244→			}
   245→
   246→			var justification = FlyoutBase.GetJustificationFromPlacementMode(popup.DesiredPlacement, FullPlacementRequested);
   247→
   248→			var fits = true;
   249→			if (!FullPlacementRequested)
   250→			{
   251→				if (IsPlacementModeVertical(placement))
   252→				{
   253→					fits = TestAndCenterAlignWithinLimits(
   254→						anchorRect.X,
   255→						anchorRect.Width,
   256→						childDesiredSize.Width,
   257→						visibleBounds.Left,
   258→						visibleBounds.Right,
   259→						justification,
   260→						out var controlXPos
   261→					);
   262→					finalPosition.X = controlXPos;
   263→				}
   264→				else
   265→				{
   266→					fits = TestAndCenterAlignWithinLimits(
   267→						anchorRect.Y,
   268→						anchorRect.Height,
   269→						childDesiredSize.Height,
   270→						visibleBounds.Top,
   271→						visibleBounds.Bottom,
   272→						justification,
   273→						out var controlYPos
   274→					);
   275→					finalPosition.Y = controlYPos;
   276→				}
   277→			}
   278→
   279→			finalRect = new Rect(finalPosition, childDesiredSize);
   280→
   281→			if (fits && RectHelper.Union(visibleBounds, finalRect).Equals(visibleBounds))
   282→			{
   283→				if (this.Log().IsEnabled(LogLevel.Debug))
   284→				{
   285→					this.Log().LogDebug($"Accepted placement {placement} (choice {i}) with finalRect={finalRect} in visibleBounds={visibleBounds}");
   286→				}
   287→				break; // this placement is acceptable
   288→			}
   289→		}
   290→
   291→		if (this.Log().IsEnabled(LogLevel.Debug))
   292→		{
   293→			this.Log().LogDebug($"Calculated placement, finalRect={finalRect}");
   294→		}
   295→
   296→		// Ensure the popup is not positioned fully beyond visible bounds.
   297→		// This can happen for example when the user is trying to show a flyout at
   298→		// Window.Current.Content - which will match Top position, which would be outside
   299→		// the visible bounds (negative Y).
   300→
   301→		if (finalRect.Bottom < visibleBounds.Top)
   302→		{
   303→			finalRect = new Rect(
   304→				finalRect.Left,
   305→				visibleBounds.Top,
   306→				finalRect.Width,
   307→				finalRect.Height);
   308→		}
   309→
   310→		if (finalRect.Top > visibleBounds.Bottom)
   311→		{
   312→			finalRect = new Rect(
   313→				finalRect.Left,
   314→				visibleBounds.Bottom - finalRect.Height,
   315→				finalRect.Width,
   316→				finalRect.Height);
   317→		}
   318→
   319→		if (finalRect.Right < visibleBounds.Left)
   320→		{
   321→			finalRect = new Rect(
   322→				visibleBounds.Left,
   323→				finalRect.Top,
   324→				finalRect.Width,
   325→				finalRect.Height);
   326→		}
   327→
   328→		if (finalRect.Left > visibleBounds.Right)
   329→		{
   330→			finalRect = new Rect(
   331→				visibleBounds.Right - finalRect.Width,
   332→				finalRect.Top,
   333→				finalRect.Width,
   334→				finalRect.Height);
   335→		}
   336→
   337→		return finalRect;
   338→	}
   339→
   340→	// Return true if placement is along vertical axis, false otherwise.
   341→	private static bool IsPlacementModeVertical(
   342→		FlyoutBase.MajorPlacementMode placementMode)
   343→	{
   344→		// We are safe even if placementMode is Full. because the case for placementMode is Full has already been put in another if branch in function PerformPlacement.
   345→		// if necessary, we can add another function : IsPlacementModeHorizontal
   346→		return (placementMode == FlyoutBase.MajorPlacementMode.Top ||
   347→				placementMode == FlyoutBase.MajorPlacementMode.Bottom);
   348→	}
   349→
   350→	// Align centers of anchor and control while keeping control coordinates within limits.
   351→	private static bool TestAndCenterAlignWithinLimits(
   352→		double anchorPos,
   353→		double anchorSize,
   354→		double controlSize,
   355→		double lowLimit,
   356→		double highLimit,
   357→		FlyoutBase.PreferredJustification justification,
   358→		out double controlPos
   359→	)
   360→	{
   361→		bool fits = true;
   362→
   363→		if (anchorSize == 0 && typeof(PopupPanel).Log().IsEnabled(LogLevel.Warning))
   364→		{
   365→			typeof(PopupPanel).Log().LogWarning($"{nameof(anchorSize)} is 0");
   366→		}
   367→
   368→		if (controlSize == 0 && typeof(PopupPanel).Log().IsEnabled(LogLevel.Warning))
   369→		{
   370→			typeof(PopupPanel).Log().LogWarning($"{nameof(anchorSize)} is 0");
   371→		}
   372→
   373→		if ((highLimit - lowLimit) > controlSize &&
   374→			anchorSize >= 0.0 &&
   375→			controlSize >= 0.0)
   376→		{
   377→
   378→			if (justification == FlyoutBase.PreferredJustification.Center)
   379→			{
   380→				controlPos = anchorPos + 0.5 * (anchorSize - controlSize);
   381→			}
   382→			else if (justification == FlyoutBase.PreferredJustification.Top || justification == FlyoutBase.PreferredJustification.Left)
   383→			{
   384→				controlPos = anchorPos;
   385→			}
   386→			else if (justification == FlyoutBase.PreferredJustification.Bottom || justification == FlyoutBase.PreferredJustification.Right)
   387→			{
   388→				controlPos = anchorPos + (anchorSize - controlSize);
   389→			}
   390→			else
   391→			{
   392→				throw new InvalidOperationException("Unsupported FlyoutBase.PreferredJustification");
   393→			}
   394→
   395→			if (controlPos < lowLimit)
   396→			{
   397→				controlPos = lowLimit;
   398→			}
   399→			else if (controlPos + controlSize > highLimit)
   400→			{
   401→				controlPos = highLimit - controlSize;
   402→			}
   403→		}
   404→		else
   405→		{
   406→			controlPos = lowLimit;
   407→			fits = false;
   408→		}
   409→
   410→		return fits;
   411→	}
   412→
   413→	private Rect GetVisibleBounds() => XamlRoot?.VisualTree.VisibleBounds ?? default;
   414→}
