   375→				Storyboard.SetTargetProperty(objectAnimation, "Margin");
   376→
   377→				var objectKeyFrames = objectAnimation.KeyFrames;
   378→
   379→				DiscreteObjectKeyFrame discreteObjectKeyFrame = new DiscreteObjectKeyFrame();
   380→
   381→				KeyTime keyTime = KeyTime.FromTimeSpan(TimeSpan.Zero);
   382→
   383→				discreteObjectKeyFrame.KeyTime = keyTime;
   384→				discreteObjectKeyFrame.Value = layoutRootPadding;
   385→
   386→				objectKeyFrames.Add(discreteObjectKeyFrame as DiscreteObjectKeyFrame);
   387→				storyboardChildren.Add(objectAnimation as ObjectAnimationUsingKeyFrames);
   388→			}
   389→
   390→			// ContentScrollViewer VerticalScrollBarVisibility
   391→			{
   392→				ObjectAnimationUsingKeyFrames objectAnimation = new ObjectAnimationUsingKeyFrames();
   393→
   394→				Storyboard.SetTarget((objectAnimation), m_tpContentScrollViewerPart);
   395→				Storyboard.SetTargetProperty(objectAnimation, "VerticalScrollBarVisibility");
   396→
   397→				var objectKeyFrames = (objectAnimation.KeyFrames);
   398→
   399→				DiscreteObjectKeyFrame discreteObjectKeyFrame = new DiscreteObjectKeyFrame();
   400→
   401→				KeyTime keyTime = KeyTime.FromTimeSpan(TimeSpan.Zero);
   402→
   403→				discreteObjectKeyFrame.KeyTime = keyTime;
   404→				discreteObjectKeyFrame.Value = contentVerticalScrollBarVisiblity;
   405→
   406→				objectKeyFrames.Add(discreteObjectKeyFrame as DiscreteObjectKeyFrame);
   407→				storyboardChildren.Add(objectAnimation as ObjectAnimationUsingKeyFrames);
   408→			}
   409→
   410→			// BackgroundElement VerticalAlignment
   411→			if (setDialogVerticalAlignment)
   412→			{
   413→				ObjectAnimationUsingKeyFrames objectAnimation = new ObjectAnimationUsingKeyFrames();
   414→
   415→				Storyboard.SetTarget(objectAnimation, m_tpBackgroundElementPart);
   416→				Storyboard.SetTargetProperty(objectAnimation, "VerticalAlignment");
   417→
   418→				var objectKeyFrames = (objectAnimation.KeyFrames);
   419→
